{
  "image_generation_prompt": {
    "subject": "A professional, high-resolution travel infographic poster for a 24-hour London walking tour.",
    "layout": {
      "format": "Vertical split layout.",
      "left_panel": {
        "description": "A cream-colored, textured marble-style background with gold ornamental borders.",
        "text_content": [
          "Main Title: '24-HOUR WALKING TOUR LONDON, UNITED KINGDOM'",
          "Subtitle: 'One City, Five Timeless Stops. A Day to Remember Forever.'",
          "Numbered List (1-5):",
          "1. Tower of London (8:00 AM) - 'Explore the ancient royal fortress.'",
          "2. Tower Bridge (9:30 AM) - 'Walk across the iconic Victorian bridge.'",
          "3. Borough Market (12:00 PM) - 'Savor tastes from London's oldest food market.'",
          "4. The Shard (3:00 PM) - 'Take in unmatched vertical city views.'",
          "5. Southbank & London Eye (7:00 PM) - 'Enjoy a twilight stroll by the Thames.'"
        ]
      },
      "right_panel": {
        "description": "An isometric, stylized bird's-eye view illustration of London along the River Thames.",
        "key_landmarks": [
          "Tower of London",
          "Tower Bridge",
          "Borough Market",
          "The Shard",
          "London Eye"
        ],
        "visual_elements": "A glowing, continuous golden path connecting the five numbered stops along the river. A nautical compass rose is positioned in the bottom-left corner.",
        "lighting_atmosphere": "Warm, cinematic sunset lighting with golden and orange hues reflecting off the water, transitioning to twilight near the London Eye."
      },
      "footer_box": {
        "location": "Bottom right corner.",
        "text_info": "TOTAL DISTANCE ~ 10 KM / 6.2 MILES | ESTIMATED TIME 24 HOURS ~ 15,000 STEPS"
      }
    },
    "style": "Elegant, polished, clean professional design, cohesive color palette of warm gold, cream, and deep sunset oranges. High-quality vector-like illustration combined with soft realistic lighting."
  }
}

{
  "image_generation_prompt": {
    "subject": "一张专业的、高分辨率的24小时伦敦步行旅游信息图海报。",
    "layout": {
      "format": "垂直分割布局。",
      "left_panel": {
        "description": "奶油色的、带有纹理的大理石风格背景，配有金色装饰边框。",
        "text_content": [
          "主标题：'24小时步行旅游 伦敦，英国'",
          "副标题：'一座城市，五个永恒的站点。难忘的一天。'",
          "编号列表 (1-5)：",
          "1. 伦敦塔 (上午 8:00) - '探索古老的皇家堡垒。'",
          "2. 塔桥 (上午 9:30) - '漫步走过标志性的维多利亚时代桥梁。'",
          "3. 博罗市场 (中午 12:00) - '品尝伦敦最古老食品市场的风味。'",
          "4. 碎片大厦 (下午 3:00) - '欣赏无与伦比的垂直城市景观。'",
          "5. 南岸与伦敦眼 (晚上 7:00) - '在泰晤士河畔享受黄昏漫步。'"
        ]
      },
      "right_panel": {
        "description": "一幅等距的、风格化的伦敦沿泰晤士河鸟瞰图插图。",
        "key_landmarks": [
          "伦敦塔",
          "塔桥",
          "博罗市场",
          "碎片大厦",
          "伦敦眼"
        ],
        "visual_elements": "一条发光的、连续的金色路径沿着河流连接这五个编号站点。左下角放置了一个航海罗盘玫瑰。",
        "lighting_atmosphere": "温暖的、电影般的日落光线，金色的和橙色的色调在水面上反射，在伦敦眼附近过渡到黄昏。"
      },
      "footer_box": {
        "location": "右下角。",
        "text_info": "总距离 ~ 10 公里 / 6.2 英里 | 预计时间 24 小时 ~ 15,000 步"
      }
    },
    "style": "优雅的、精良的、干净的专业设计，暖金色、奶油色和深日落橙色的协调调色板。高质量的矢量风格插图结合柔和的现实主义光线。"
  }
}

