{
  "task": "Generate a high-quality vertical Popular Science Encyclopedia Image",
  "subject": "Sharks",
  "format": "Vertical modular popular science infographic",
  "style_references": [
    "High-end natural history illustrations",
    "Modern encyclopedia pages",
    "Lifestyle knowledge cards",
    "Highly shareable social media infographics"
  ],
  "style_description": "Illustration book aesthetic combined with encyclopedia structure, information density, and collectability. NOT a commercial poster.",
  "required_visual_elements": {
    "main_visual": "A clear and beautiful central illustration of a shark (e.g., Great White Shark) in full profile view, rendered in detailed naturalist style",
    "magnified_details": [
      "Close-up of shark teeth rows",
      "Dermal denticles (skin texture)",
      "Ampullae of Lorenzini (electroreceptor pores on snout)",
      "Caudal fin structure"
    ],
    "information_modules": "Multiple rounded modular info boxes with soft shadows and light backgrounds",
    "title_hierarchy": "Clear main title, subtitle, and section labels with consistent typographic scale",
    "icons": "Small exquisite icons accompanying each data point or module header"
  },
  "content_modules": [
    {
      "module": "Basic Profile",
      "fields": [
        "Scientific name",
        "Common name",
        "Lifespan",
        "Average size",
        "Weight range",
        "Habitat depth range"
      ]
    },
    {
      "module": "Classification Info",
      "fields": [
        "Kingdom",
        "Class",
        "Order",
        "Family",
        "Number of known species (~500)"
      ]
    },
    {
      "module": "Appearance Characteristics",
      "fields": [
        "Body shape",
        "Skin texture (dermal denticles)",
        "Coloration",
        "Fin types and functions",
        "Eye structure"
      ]
    },
    {
      "module": "Habits & Ecology",
      "fields": [
        "Diet",
        "Hunting strategy",
        "Migration patterns",
        "Social behavior",
        "Reproduction method (oviparous / viviparous / ovoviviparous)"
      ]
    },
    {
      "module": "Unique Biological Structures",
      "fields": [
        "Lateral line system",
        "Electroreception (Ampullae of Lorenzini)",
        "Multiple rows of teeth (polyphyodont)",
        "Cartilaginous skeleton",
        "Countershading camouflage"
      ]
    },
    {
      "module": "Ecosystem Role",
      "fields": [
        "Apex predator status",
        "Role in marine food web",
        "Impact on prey population balance",
        "Indicator species for ocean health"
      ]
    },
    {
      "module": "Risks & Conservation",
      "fields": [
        "Threats: overfishing, finning, bycatch, habitat loss",
        "IUCN status of key species",
        "Legal protections",
        "Human encounter risk (context)"
      ]
    },
    {
      "module": "Top 5 Most Notable Species",
      "entries": [
        "Great White Shark – largest predatory fish",
        "Whale Shark – largest fish on Earth",
        "Hammerhead Shark – unique cephalofoil head",
        "Bull Shark – tolerates freshwater",
        "Shortfin Mako – fastest shark species"
      ]
    },
    {
      "module": "Quick Rating Card",
      "ratings": [
        {
          "trait": "Speed",
          "score": "4.5/5"
        },
        {
          "trait": "Danger to humans",
          "score": "3/5"
        },
        {
          "trait": "Intelligence",
          "score": "3.5/5"
        },
        {
          "trait": "Conservation urgency",
          "score": "4.5/5"
        },
        {
          "trait": "Ecological importance",
          "score": "5/5"
        }
      ]
    },
    {
      "module": "Fast Facts / Key Point Summary",
      "facts": [
        "Sharks have existed for over 450 million years — predating the dinosaurs",
        "They have no bones — their skeleton is entirely cartilage",
        "Some species must swim continuously to breathe (obligate ram ventilators)",
        "A shark may grow and shed tens of thousands of teeth in its lifetime",
        "Fewer than 10 unprovoked fatal attacks occur globally per year"
      ]
    }
  ],
  "visual_design_requirements": {
    "background": "Light-colored, clean — off-white, pale blue-gray, or warm cream",
    "color_palette": "Soft and natural: ocean blues, sandy beiges, coral accents, dark navy for text",
    "shadows": "Subtle light drop shadows on module cards",
    "corners": "Rounded rectangles for all information boxes",
    "layout": "High information density but not crowded; generous internal padding; neat grid structure",
    "typography": "Clear hierarchy: large title > section headers > body text > labels/captions",
    "orientation": "Vertical / portrait format",
    "icons": "Small, exquisite line or flat icons per module",
    "overall_feel": "Looks like a real printed science encyclopedia card — suitable for publishing, reading, collecting, and serialized production"
  },
  "explicitly_not": [
    "Not a commercial advertisement",
    "Not a promotional poster",
    "Not a simple single illustration",
    "No sales messaging or branding language"
  ],
  "emphasis": "Knowledge organization + modular information layout + naturalist illustration-style display"
}

{
